import React, { useState } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Alert,
  Box,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupRider, uploadRiderDocs } from "../services/api";

export default function RiderRegister() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "" });
  const [documents, setDocuments] = useState([]);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  // Validate file type and size
  const validateFile = (file) => {
    if (!file) return false;
    const validTypes = ["image/jpeg", "image/png", "image/jpg"];
    const maxSize = 5 * 1024 * 1024; // 5MB
    if (!validTypes.includes(file.type)) {
      setError("Only JPG/PNG images are allowed.");
      return false;
    }
    if (file.size > maxSize) {
      setError("File size should be less than 5MB.");
      return false;
    }
    return true;
  };

  // Handle text input
  const handleChange = (e) =>
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));

  // Handle file input
  const handleFileChange = (e) => {
    setError("");
    const files = Array.from(e.target.files);
    const validFiles = files.filter(validateFile);
    setDocuments((prev) => [...prev, ...validFiles]);
  };

  // Remove selected file
  const removeFile = (index) => {
    setDocuments((prev) => prev.filter((_, i) => i !== index));
  };

  // Handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setLoading(true);

    if (!documents.length) {
      setError("Please upload at least one document.");
      setLoading(false);
      return;
    }

    try {
      // 1️⃣ Signup rider
      const res = await signupRider({ ...formData, role: "rider" });
      const riderId = res.data?.data?.id || res.data?.data?._id;
      if (!riderId) throw new Error("No Rider ID returned from server.");

      // 2️⃣ Upload documents
      const formDataUpload = new FormData();
      documents.forEach((file) => formDataUpload.append("documents", file));
      await uploadRiderDocs(riderId, formDataUpload);

      setSuccess("Registered successfully! Waiting for admin approval.");
      setTimeout(() => navigate("/rider-login"), 2500);
    } catch (err) {
      console.error("Rider signup error:", err);
      setError(err.response?.data?.message || err.message || "Server error. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 4, borderRadius: 3, textAlign: "center", boxShadow: 5 }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
          Rider Signup
        </Typography>
        <Typography variant="body2" sx={{ mb: 3, color: "gray" }}>
          Join as a rider — create your account and upload documents.
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <form onSubmit={handleSubmit}>
          <TextField
            fullWidth
            label="Full Name"
            name="fullName"
            value={formData.fullName}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            type="email"
            label="Email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            type="tel"
            label="Mobile Number"
            name="mobile"
            value={formData.mobile}
            onChange={handleChange}
            margin="normal"
            inputProps={{ maxLength: 10 }}
            required
          />

          <Typography variant="h6" sx={{ mt: 3, mb: 1 }}>Upload Documents</Typography>
          <Box sx={{ display: "flex", flexDirection: "column", gap: 1, textAlign: "left" }}>
            <input type="file" multiple onChange={handleFileChange} />
            {documents.length > 0 && (
              <Box>
                <Typography variant="body2" sx={{ mt: 1 }}>Selected files:</Typography>
                <ul>
                  {documents.map((file, idx) => (
                    <li key={idx}>
                      {file.name}{" "}
                      <Button size="small" onClick={() => removeFile(idx)}>Remove</Button>
                    </li>
                  ))}
                </ul>
              </Box>
            )}
          </Box>

          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ mt: 3, bgcolor: "black", fontWeight: "bold" }}
            disabled={loading}
          >
            {loading ? <CircularProgress size={24} color="inherit" /> : "Sign Up"}
          </Button>
        </form>

        <Typography sx={{ mt: 2 }}>
          Already have an account?{" "}
          <Button onClick={() => navigate("/rider-login")} sx={{ fontWeight: "bold" }}>
            LOGIN
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
